// 取出 summary（可放入每行一起記錄）
const summary = $json.summary;
// 記錄日期時間
const now = new Date().toISOString();


// 拉出 details 陣列
const items = $json.details.map(d => ({
  summary,
  meal_time: d.meal_time ?? "",
  food_name: d.food_name ?? "",
  main_ingredient: d.main_ingredient ?? "",
  cooking_method: d.cooking_method ?? "",
  sauce_or_seasoning: d.sauce_or_seasoning ?? "",
  style: d.style ?? "",
  calories: d.nutrition?.calories ?? "",
  protein: d.nutrition?.protein ?? "",
  fat: d.nutrition?.fat ?? "",
  carbohydrates: d.nutrition?.carbohydrates ?? "",
  fiber: d.nutrition?.fiber ?? "",
  record_date_time:now
}));

return items.map(i => ({ json: i }));

/**
 * Robust JSON repair + parse
 * Handles missing quotes, double-escaped input, stray newlines, etc.
 */

let raw = $input.first().json.output || "";
if (typeof raw !== "string") raw = JSON.stringify(raw);

// Step 1: remove markdown wrappers
raw = raw.replace(/^```(json)?/i, "").replace(/```$/, "").trim();

// Step 2: normalize escapes
raw = raw
  .replace(/\\n/g, "\n")
  .replace(/\\"/g, '"')
  .replace(/\\\\/g, "\\");

// Step 3: auto‑repair common key errors like:  ,\n style":
raw = raw.replace(/(\n|\r|\s)style":/g, '\n"style":');
raw = raw.replace(/([{,]\s*)([A-Za-z_][A-Za-z0-9_]*)(\s*):/g, '$1"$2"$3:');

// Step 4: remove trailing commas
raw = raw.replace(/,\s*([}\]])/g, '$1');

// Step 5: try parsing (two‑layer fallback)
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err1) {
  try {
    parsed = JSON.parse(JSON.parse(raw));
  } catch (err2) {
    return [{
      json: {
        error: "❌ Could not parse JSON even after auto‑repair",
        message1: err1.message,
        message2: err2.message,
        preview: raw.slice(0, 600)
      }
    }];
  }
}

// ✅ Successfully parsed
return [{ json: parsed }];

// 1. Fetch results first
let results = $('Custom Code: Parse the Output from AI Agent').first().json.details || [];

// 2. Combine the parsed food names and meal times to detect the language
let textToAnalyze = "";
results.forEach(r => {
  textToAnalyze += (r.meal_time || "") + (r.food_name || "");
});

// Fallback to incoming message just in case
const incoming = $input.first().json.message || "";
const textForDetection = textToAnalyze + incoming;

// 3. Better pattern detection based on the combined text
const hasKana = /[\u3040-\u30ff\u31f0-\u31ff\uFF66-\uFF9F]/.test(textForDetection);
const hasHanzi = /[\u4e00-\u9fa5]/.test(textForDetection);

// 4. Determine Language First
let language = "English";
if (hasKana) {
  language = "Japanese";
} else if (hasHanzi) {
  language = "Chinese";
}

// Timestamp
const now = new Date();
const dateOptions = { year: 'numeric', month: 'short', day: 'numeric' };
const timeOptions = { hour: 'numeric', minute: '2-digit', second: '2-digit' };

// Set up localized labels (added "total") and reply headers
let labels = {
  calories: "Calories",
  fats: "Fats",
  protein: "Protein",
  carbs: "Carbohydrates",
  fiber: "Fibers",
  total: "Total"
};
let replyHeader = `Your record has been saved on ${now.toLocaleDateString('en-GB', dateOptions)} at ${now.toLocaleTimeString('en-GB', timeOptions)}. Thank you for using this system!\n\nRecord Details:\n`;

if (language === "Japanese") {
  labels = { calories: "カロリー", fats: "脂質", protein: "タンパク質", carbs: "炭水化物", fiber: "食物繊維", total: "合計" };
  replyHeader = `あなたの記録は ${now.toLocaleDateString('ja-JP', dateOptions)} ${now.toLocaleTimeString('ja-JP', timeOptions)} に保存されました。ご利用ありがとうございます！\n\n記録内容:\n`;
} else if (language === "Chinese") {
  labels = { calories: "卡路里", fats: "脂肪", protein: "蛋白質", carbs: "碳水化合物", fiber: "纖維", total: "總計" };
  replyHeader = `你嘅紀錄已經存檔在 ${now.toLocaleDateString('zh-HK', dateOptions)} ${now.toLocaleTimeString('zh-HK', timeOptions)}，多謝使用本系統！\n\n紀錄內容:\n`;
}

// Helper function to extract only the numbers from strings like "30g" or "500 kcal"
const extractNumber = (val) => {
  const num = parseFloat(String(val).replace(/[^0-9.]/g, ''));
  return isNaN(num) ? 0 : num;
};

// Variables to keep track of the totals
let totalCalories = 0;
let totalFats = 0;
let totalProtein = 0;
let totalCarbs = 0;
let totalFiber = 0;

// Build the display details
let display_details = "";
results.forEach((result) => {
  // Add current meal's nutrition to the totals
  totalCalories += extractNumber(result.nutrition.calories);
  totalFats += extractNumber(result.nutrition.fat);
  totalProtein += extractNumber(result.nutrition.protein);
  totalCarbs += extractNumber(result.nutrition.carbohydrates);
  totalFiber += extractNumber(result.nutrition.fiber);

  display_details += `- ${result.meal_time}: ${result.food_name} (${labels.calories}: ${result.nutrition.calories}, ${labels.fats}: ${result.nutrition.fat}, ${labels.protein}: ${result.nutrition.protein}, ${labels.carbs}: ${result.nutrition.carbohydrates}, ${labels.fiber}: ${result.nutrition.fiber})\n`;
});

// Append the Total row at the bottom
display_details += `\n- ${labels.total}: (${labels.calories}: ${totalCalories}, ${labels.fats}: ${totalFats}g, ${labels.protein}: ${totalProtein}g, ${labels.carbs}: ${totalCarbs}g, ${labels.fiber}: ${totalFiber}g)\n`;

// Combine the header and the details
const reply = display_details;

return [{ json: { language, reply } }];
